var sys_activityID = "";
var sys_config = "";
var game_logo = "";
var game_id = "";

var share_title = "牵着你的手～心跳在加速～";
var share_message = "这游戏很有难度的说，快来试试吧！";
var share_image = "/game/img/sharelogo/226030.png";
var share_href = location.href;


function getpara()//获取参数的函数
{
    var url = document.URL; // http://www.wesane.com/Public/Games/326029/201506080259455561/html5/index.html?gameID=226030&from=singlemessage&isappinstalled=0
    var config_info = "";   
    var para="";    
    if(url.lastIndexOf("?")>0) {    
        para = url.substring(url.lastIndexOf("?") + 1, url.length); 
        var arr = para.split("&"); //用于把一个字符串分割成字符串数组。 gameID=226030 & from=singlemessage & isappinstalled=0  =  ['gameID=226030','from=singlemessage'，‘isappinstalled=0’ ]
        if (arr[0].split("=")[0] == "activityID") {  // arr[0] = 'gameID 226030'   分割 arr[0].split('=') = 'gameID=226030' 
            sys_activityID = arr[0].split("=")[1]; //sys_activityID = 'activityID'
        }else{
            if (arr[0].split("=")[0] == "gameID") {
                game_id = arr[0].split("=")[1]; // game_id = '226030'     gameID=226030
            };
            document.getElementById("logoImg").style.display = "block";
        }
    }else{
        document.getElementById("logoImg").style.display = "block";
    }

}
// 彻底理解了split和substring的意思，split表示分割已经有的字符串的特殊字符。如：var the = is&and&no。 the.split('&') //return [ is , and , no ]
// substring() 如:var the = '234567'。 the.substring(2) // return 3456 也就是输出第二位到最后的数字，如果自定义就更加容易 substring(2,3)就是输出3、4，从第二到第三数



// ajax处理json数据
function gamelogo_load() {
    ajaxLoad("/admin/json/gamelogo.json", "activityId=" + sys_activityID + "&gameID=" + game_id, ajaxOnLogoResult);
    // activityId=226030&gameID=226030
}

// ajax处理json数据
function btn_onClickHandler() {
    var sharelink = location.href;
    ajaxLoad("/admin/json/weixinShare.json", "shareUrl=" + encodeURIComponent(sharelink.split("#")[0]) + "&activityId=" + sys_activityID, ajaxOnResult);
}

/* function onload 函数内部加载   */
function ajaxLoad(uri, postData, callback) {
    var request = (window.XMLHttpRequest) ? new XMLHttpRequest() : new ActiveXObject("Microsoft.XMLHTTP");
    request.onreadystatechange = callback;
    request.open("Get", uri);
    request.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
    request.send(postData);
}


/* 函数加载条件 最为callback 回调函数   */
function ajaxOnResult(evt) {
    if ((evt.currentTarget.readyState == 4) && (evt.currentTarget.status == 200 || evt.currentTarget.status == 0)) {

        var sys_config = JSON.parse(evt.currentTarget.responseText);

        if(sys_config["weixinResult"] != ""){
            share_title = sys_config["weixinResult"]["weixin_title"];
            share_message = sys_config["weixinResult"]["weixin_content"];
            share_image = "http://www.wesane.com/Public/"+sys_config["weixinResult"]["weixin_savepath"];
            share_href = "http://www.wesane.com/admin.php/Activityshow/getActivityById/activityId/"+sys_activityID;
        }

        wx.config({
            debug: false,
            appId: sys_config["appId"],
            timestamp: sys_config["timestamp"],
            nonceStr: sys_config["nonceStr"],
            signature: sys_config["signature"],
            jsApiList: [
                'checkJsApi',
                'onMenuShareTimeline',
                'onMenuShareAppMessage',
                'onMenuShareQQ',
                'onMenuShareWeibo',
                'hideMenuItems',
                'showMenuItems',
                'getNetworkType',
                'hideOptionMenu',
                'showOptionMenu',
                'closeWindow'
            ]
        });
        wx.ready(function () {
            // 在这里调用 API

            var title = share_title;
            var message = share_message;
            var sharelink = share_href.split("#")[0];
            var imgUrl =share_image;
            wx.onMenuShareTimeline({
                title: title, // 分享标题
                link: sharelink, // 分享链接
                imgUrl: imgUrl, // 分享图标
                success: function () {
                    // 用户确认分享后执行的回调函数
                    //alert("喵喵感谢您！");
                },
                cancel: function () {
                    // 用户取消分享后执行的回调函数
                }
            });

            wx.onMenuShareAppMessage({
                title: title, // 分享标题
                desc: message, // 分享描述
                link: sharelink, // 分享链接
                imgUrl: imgUrl, // 分享图标
                success: function () {
                    // 用户确认分享后执行的回调函数
                },
                cancel: function () {
                    // 用户取消分享后执行的回调函数
                }
            });
            wx.onMenuShareQQ({
                title: title, // 分享标题
                desc: message, // 分享描述
                link: sharelink, // 分享链接
                imgUrl: imgUrl, // 分享图标
                success: function () {
                    // 用户确认分享后执行的回调函数
                },
                cancel: function () {
                    // 用户取消分享后执行的回调函数
                }
            });
            wx.onMenuShareWeibo({
                title: title, // 分享标题
                desc: message, // 分享描述
                link: sharelink, // 分享链接
                imgUrl: imgUrl, // 分享图标
                success: function () {
                    // 用户确认分享后执行的回调函数
                },
                cancel: function () {
                    // 用户取消分享后执行的回调函数
                }
            });
        });

    }
}


